triple_if_case.solution:
Lemma triple_if_case : forall b t1 t2 H Q,
  (b = true -> triple t1 H Q) ->
  (b = false -> triple t2 H Q) ->
  triple (trm_if (val_bool b) t1 t2) H Q.
Proof using.
  introv M1 M2. intros h Hh. destruct b.
  { lets (h'&v&R&HQ): M1 __ Hh. exists h' v. splits.
    { applys eval_if. auto. }
    { auto. } }
  { lets (h'&v&R&HQ): M2 __ Hh. exists h' v. splits.
    { applys eval_if. auto. }
    { auto. } }
Qed.

triple_val'.solution:
Lemma triple_val' : forall v H Q,
  H ==> Q v ->
  triple (trm_val v) H Q.
Proof using.
  introv M. applys triple_conseq.
  { applys triple_val. { xsimpl. } }
  { xsimpl. applys M. }
  { xsimpl. }
Qed.

triple_rand.solution:
Lemma triple_rand : forall n,
  n > 0 ->
  triple (val_rand n)
    \[]
    (fun r => \exists m, \[r = val_int m] \* \[0 <= m < n]).
Proof using.
  introv Hn. intros h Hh. lets E: hempty_inv Hh. subst.
  lets (m&Hm&R): eval_rand Hn \{}
  exists (Fmap.empty) m. splits.
  { applys R. }
  { exists m. rewrite hstar_hpure_l. splits. { auto. }
    rewrite hstar_hpure_l. auto. }
Qed.

triple_succ_using_incr.solution:
Lemma triple_succ_using_incr : forall (n:int),
  triple (succ_using_incr n)
    \[]
    (fun r => \[r = n + 1]).
Proof using.
  intros. applys triple_let.
  { applys triple_ref. }
  { intros p. simpl. applys triple_let.
    { applys triple_seq.
      { applys triple_incr. }
      { applys triple_get. } }
    { intros v. simpl. applys triple_let.
      { applys triple_free. }
      { intros _. simpl. applys triple_val. xsimpl. math. } } }
Qed.
